/**
 * Stockage hors-ligne pour les collecteurs.
 * Utilise IndexedDB pour stocker les formulaires en attente de synchronisation.
 */ const DB_NAME = "digiparc-offline";
const DB_VERSION = 1;
const STORE_NAME = "pending-parcelles";
function openDB() {
    return new Promise((resolve, reject)=>{
        const request = indexedDB.open(DB_NAME, DB_VERSION);
        request.onupgradeneeded = (event)=>{
            const db = event.target.result;
            if (!db.objectStoreNames.contains(STORE_NAME)) {
                db.createObjectStore(STORE_NAME, {
                    keyPath: "id",
                    autoIncrement: true
                });
            }
        };
        request.onsuccess = ()=>resolve(request.result);
        request.onerror = ()=>reject(request.error);
    });
}
async function saveOfflineParcelle(data) {
    const db = await openDB();
    return new Promise((resolve, reject)=>{
        const tx = db.transaction(STORE_NAME, "readwrite");
        const store = tx.objectStore(STORE_NAME);
        const entry = {
            data,
            createdAt: new Date().toISOString(),
            synced: false
        };
        const request = store.add(entry);
        request.onsuccess = ()=>resolve(request.result);
        request.onerror = ()=>reject(request.error);
    });
}
async function getPendingParcelles() {
    const db = await openDB();
    return new Promise((resolve, reject)=>{
        const tx = db.transaction(STORE_NAME, "readonly");
        const store = tx.objectStore(STORE_NAME);
        const request = store.getAll();
        request.onsuccess = ()=>{
            const all = request.result;
            resolve(all.filter((p)=>!p.synced));
        };
        request.onerror = ()=>reject(request.error);
    });
}
async function markAsSynced(id) {
    const db = await openDB();
    return new Promise((resolve, reject)=>{
        const tx = db.transaction(STORE_NAME, "readwrite");
        const store = tx.objectStore(STORE_NAME);
        const getReq = store.get(id);
        getReq.onsuccess = ()=>{
            const entry = getReq.result;
            if (entry) {
                entry.synced = true;
                store.put(entry);
            }
            resolve();
        };
        getReq.onerror = ()=>reject(getReq.error);
    });
}
async function clearSyncedParcelles() {
    const db = await openDB();
    return new Promise((resolve, reject)=>{
        const tx = db.transaction(STORE_NAME, "readwrite");
        const store = tx.objectStore(STORE_NAME);
        const request = store.getAll();
        request.onsuccess = ()=>{
            const all = request.result;
            all.forEach((entry)=>{
                if (entry.synced && entry.id) store.delete(entry.id);
            });
            resolve();
        };
        request.onerror = ()=>reject(request.error);
    });
}
async function syncPendingParcelles() {
    const pending = await getPendingParcelles();
    let synced = 0;
    let failed = 0;
    for (const entry of pending){
        try {
            const res = await fetch("/api/parcelles", {
                method: "POST",
                headers: {
                    "Content-Type": "application/json"
                },
                body: JSON.stringify(entry.data)
            });
            if (res.ok && entry.id) {
                await markAsSynced(entry.id);
                synced++;
            } else {
                failed++;
            }
        } catch  {
            failed++;
        }
    }
    if (synced > 0) await clearSyncedParcelles();
    return {
        synced,
        failed
    };
}
function isOnline() {
    return typeof navigator !== "undefined" ? navigator.onLine : true;
}
async function countPending() {
    const pending = await getPendingParcelles();
    return pending.length;
}
